  1	import type { FC } from 'react';
  2	import HelpIconWithLabel from 'src/plans/components/HelpIconWithLabel';
  3	import { getMigrationTypeConfig } from 'src/plans/create/steps/migration-type/utils';
  4	import { hasLiveMigrationProviderType } from 'src/plans/create/utils/hasLiveMigrationProviderType';
  5	import { hasWarmMigrationProviderType } from 'src/plans/create/utils/hasWarmMigrationProviderType';
  6	
  7	import { ExternalLink } from '@components/common/ExternalLink/ExternalLink';
  8	import type { ProviderVirtualMachine, V1beta1Provider } from '@kubev2v/types';
  9	import { Alert, FlexItem, Radio, Split, SplitItem, Stack, StackItem } from '@patternfly/react-core';
 10	import { isEmpty } from '@utils/helpers';
 11	import { useForkliftTranslation } from '@utils/i18n';
 12	import { CBT_HELP_LINK } from '@utils/links';
 13	
 14	import { migrationTypeLabels, MigrationTypeValue } from './constants';
 15	
 16	type MigrationTypeRadioProps = {
 17	  migrationType: MigrationTypeValue;
 18	  value: MigrationTypeValue;
 19	  onChange: (val: MigrationTypeValue) => void;
 20	  sourceProvider?: V1beta1Provider;
 21	  cbtDisabledVms?: ProviderVirtualMachine[];
 22	};
 23	
 24	const MigrationTypeRadio: FC<MigrationTypeRadioProps> = ({
 25	  cbtDisabledVms = [],
 26	  migrationType,
 27	  onChange,
 28	  sourceProvider,
 29	  value,
 30	}) => {
 31	  const { t } = useForkliftTranslation();
 32	
 33	  const canRender =
 34	    migrationType === MigrationTypeValue.Cold ||
 35	    (migrationType === MigrationTypeValue.Warm && hasWarmMigrationProviderType(sourceProvider)) ||
 36	    (migrationType === MigrationTypeValue.Live && hasLiveMigrationProviderType(sourceProvider));
 37	
 38	  if (!canRender) return null;
 39	
 40	  const { description, helpBody, helpLink, PreviewLabel } = getMigrationTypeConfig(migrationType);
 41	
 42	  return (
 43	    <>
 44	      <FlexItem>
 45	        <Radio
 46	          id={migrationType}
 47	          name={migrationType}
 48	          label={
 49	            helpBody ? (
 50	              <Split hasGutter>
 51	                <SplitItem>
 52	                  <HelpIconWithLabel label={migrationTypeLabels[migrationType]}>
 53	                    <Stack hasGutter>
 54	                      <StackItem>{helpBody}</StackItem>
 55	                      <StackItem>
 56	                        <ExternalLink isInline href={helpLink!}>
 57	                          {t('Learn more')}
 58	                        </ExternalLink>
 59	                      </StackItem>
 60	                    </Stack>
 61	                  </HelpIconWithLabel>
 62	                </SplitItem>
 63	                {PreviewLabel && (
 64	                  <SplitItem>
 65	                    <PreviewLabel />
 66	                  </SplitItem>
 67	                )}
 68	              </Split>
 69	            ) : (
 70	              migrationTypeLabels[migrationType]
 71	            )
 72	          }
 73	          description={description}
 74	          isChecked={value === migrationType}
 75	          onChange={() => {
 76	            onChange(migrationType);
 77	          }}
 78	        />
 79	      </FlexItem>
 80	
 81	      {migrationType === MigrationTypeValue.Warm &&
 82	        value === MigrationTypeValue.Warm &&
 83	        !isEmpty(cbtDisabledVms) && (
 84	          <Alert
 85	            isInline
 86	            variant="warning"
 87	            title={t('Must enable Changed Block Tracking (CBT) for warm migration')}
 88	            className="pf-v6-u-ml-lg"
 89	          >
 90	            <Stack hasGutter>
 91	              <p>
 92	                {cbtDisabledVms.length} {t('of your selected VMs do not have CBT enabled.')}
 93	                <br />
 94	                {t(
 95	                  'Switch those VMs to cold migration or enable CBT in VMware before running the plan; otherwise the migration will fail.',
 96	                )}
 97	              </p>
 98	              <ExternalLink isInline href={CBT_HELP_LINK}>
 99	                {t('Learn more')}
100	              </ExternalLink>
101	            </Stack>
102	          </Alert>
103	        )}
104	    </>
105	  );
106	};
107	
108	export default MigrationTypeRadio;

